159			log("        print the temp dir name in log. usually this is suppressed so that the\n");
160			log("        command output is identical across runs.\n");
161			log("\n");
162			log("    -box <file>\n");
163			log("        pass this file with box library to ABC.\n");
164			log("\n");
165			log("Note that this is a logic optimization pass within Yosys that is calling ABC\n");
166			log("internally. This is not going to \"run ABC on your design\". It will instead run\n");
167			log("ABC on logic snippets extracted from your design. You will not get any useful\n");
168			log("output when passing an ABC script that writes a file. Instead write your full\n");
169			log("design as an XAIGER file with `write_xaiger' and then load that into ABC\n");
170			log("externally if you want to use ABC to convert your design into another format.\n");
171			log("\n");
172			log("[1] http://www.eecs.berkeley.edu/~alanmi/abc/\n");
173			log("\n");
174			help_script();
175			log("\n");
176		}
177	
178		std::stringstream exe_cmd;
179		bool dff_mode, cleanup;
180		bool lut_mode;
181		int maxlut;
182		std::string box_file;
183	
184		void clear_flags() override
185		{
186			exe_cmd.str("");
187			exe_cmd << "abc9_exe";
188			dff_mode = false;
189			cleanup = true;
190			lut_mode = false;
191			maxlut = 0;
192			box_file = "";
193		}
194	
195		void execute(std::vector<std::string> args, RTLIL::Design *design) override
196		{
197			std::string run_from, run_to;
198			clear_flags();
199	
200			// get arguments from scratchpad first, then override by command arguments
201			dff_mode = design->scratchpad_get_bool("abc9.dff", dff_mode);
202			cleanup = !design->scratchpad_get_bool("abc9.nocleanup", !cleanup);
203	
204			if (design->scratchpad_get_bool("abc9.debug")) {
205				cleanup = false;
206				exe_cmd << " -showtmp";
207			}
208	
209			size_t argidx;
210			for (argidx = 1; argidx < args.size(); argidx++) {
211				std::string arg = args[argidx];
212				if ((arg == "-exe" || arg == "-script" || arg == "-D" ||
213							arg == "-lut" || arg == "-luts" || arg == "-W") &&
214						argidx+1 < args.size()) {
215					if (arg == "-lut" || arg == "-luts")
216						lut_mode = true;
217					exe_cmd << " " << arg << " " << args[++argidx];
218					continue;
219				}
220				if (arg == "-showtmp") {
221					exe_cmd << " " << arg;
222					continue;
223				}
224				if (arg == "-dff") {
225					dff_mode = true;
226					exe_cmd << " " << arg;
227					continue;
228				}
229				if (arg == "-nocleanup") {
230					cleanup = false;
231					continue;
232				}
233				if (arg == "-box" && argidx+1 < args.size()) {
234					box_file = args[++argidx];
235					continue;
236				}
237				if (arg == "-maxlut" && argidx+1 < args.size()) {
238					maxlut = atoi(args[++argidx].c_str());
239					continue;
240				}
241				if (arg == "-run" && argidx+1 < args.size()) {
242					size_t pos = args[argidx+1].find(':');
243					if (pos == std::string::npos)
244						break;
245					run_from = args[++argidx].substr(0, pos);
246					run_to = args[argidx].substr(pos+1);
247					continue;
248				}
249				break;
250			}
251			extra_args(args, argidx, design);
252	
253			if (maxlut && lut_mode)
254				log_cmd_error("abc9 '-maxlut' option only applicable without '-lut' nor '-luts'.\n");
255	
256			log_assert(design);
257			if (design->selected_modules().empty()) {
258				log_warning("No modules selected for ABC9 techmapping.\n");
259				return;
260			}
261	
262			log_header(design, "Executing ABC9 pass.\n");
263			log_push();
264	
265			run_script(design, run_from, run_to);
266	
267			log_pop();
268		}
269	
270		void script() override
271		{
272			if (check_label("check")) {
273				if (help_mode)
274					run("abc9_ops -check [-dff]", "(option if -dff)");
275				else
276					run(stringf("abc9_ops -check %s", dff_mode ? "-dff" : ""));
277			}
278	
279			if (check_label("map")) {
280				if (help_mode)
281					run("abc9_ops -prep_hier [-dff]", "(option if -dff)");
282				else
283					run(stringf("abc9_ops -prep_hier %s", dff_mode ? "-dff" : ""));
284				run("scc -specify -set_attr abc9_scc_id {}");
285				if (help_mode)
286					run("abc9_ops -prep_bypass [-prep_dff]", "(option if -dff)");
287				else {
288					active_design->scratchpad_unset("abc9_ops.prep_bypass.did_something");
289					run(stringf("abc9_ops -prep_bypass %s", dff_mode ? "-prep_dff" : ""));
290				}
291				if (dff_mode) {
292					run("design -copy-to $abc9_map @$abc9_flops", "(only if -dff)");
293					run("select -unset $abc9_flops", "             (only if -dff)");
294				}
295				run("design -stash $abc9");
296				run("design -load $abc9_map");
297				if (help_mode) run("select =*");
298				else active_design->push_complete_selection();
299				run("wbflip");
300				run("techmap -autoproc -wb -map %$abc9 -map +/techmap.v A:abc9_flop");
301				run("opt -nodffe -nosdff");
302				if (dff_mode || help_mode) {
303					if (!help_mode)
304						active_design->scratchpad_unset("abc9_ops.prep_dff_submod.did_something");
305					run("abc9_ops -prep_dff_submod", "                                                 (only if -dff)"); // rewrite specify
306					bool did_something = help_mode || active_design->scratchpad_get_bool("abc9_ops.prep_dff_submod.did_something");
307					if (did_something) {
308											// select all $_DFF_[NP]_
309											// then select all its fanins
310											// then select all fanouts of all that
311											// lastly remove $_DFF_[NP]_ cells
312						run("setattr -set submod \"$abc9_flop\" t:$_DFF_?_ %ci* %co* t:$_DFF_?_ %d", "       (only if -dff)");
313						run("submod", "                                                                    (only if -dff)");
314						run("setattr -mod -set whitebox 1 -set abc9_flop 1 -set abc9_box 1 *_$abc9_flop", "(only if -dff)");
