497	static void dfflibmap(RTLIL::Design *design, RTLIL::Module *module)
498	{
499		log("Mapping DFF cells in module `%s':\n", module->name);
500	
501		dict<SigBit, pool<Cell*>> notmap;
502		SigMap sigmap(module);
503	
504		std::vector<RTLIL::Cell*> cell_list;
505		for (auto cell : module->cells()) {
506			if (design->selected(module, cell) && cell_mappings.count(cell->type) > 0)
507				cell_list.push_back(cell);
508			if (cell->type == ID($_NOT_))
509				notmap[sigmap(cell->getPort(ID::A))].insert(cell);
510		}
511	
512		std::map<std::string, int> stats;
513		for (auto cell : cell_list)
514		{
515			auto cell_type = cell->type;
516			auto cell_name = cell->name;
517			auto cell_connections = cell->connections();
518			std::string src = cell->get_src_attribute();
519	
520			module->remove(cell);
521	
522			cell_mapping &cm = cell_mappings[cell_type];
523			RTLIL::Cell *new_cell = module->addCell(cell_name, cm.cell_name);
524	
525			new_cell->set_src_attribute(src);
526	
527			bool has_q = false, has_qn = false;
528			for (auto &port : cm.ports) {
529				if (port.second == 'Q') has_q = true;
530				if (port.second == 'q') has_qn = true;
531			}
532	
533			for (auto &port : cm.ports) {
534				RTLIL::SigSpec sig;
535				if ('A' <= port.second && port.second <= 'Z') {
536					sig = cell_connections[std::string("\\") + port.second];
537				} else
538				if (port.second == 'q') {
539					RTLIL::SigSpec old_sig = cell_connections[std::string("\\") + char(port.second - ('a' - 'A'))];
540					sig = module->addWire(NEW_ID, GetSize(old_sig));
541					if (has_q && has_qn) {
542						for (auto &it : notmap[sigmap(old_sig)]) {
543							module->connect(it->getPort(ID::Y), sig);
544							it->setPort(ID::Y, module->addWire(NEW_ID, GetSize(old_sig)));
545						}
546					} else {
547						module->addNotGate(NEW_ID, sig, old_sig);
548					}
549				} else
550				if ('a' <= port.second && port.second <= 'z') {
551					sig = cell_connections[std::string("\\") + char(port.second - ('a' - 'A'))];
552					sig = module->NotGate(NEW_ID, sig);
553				} else
554				if (port.second == '0' || port.second == '1') {
555					sig = RTLIL::SigSpec(port.second == '0' ? 0 : 1, 1);
556				} else
557				if (port.second == 0) {
558					sig = module->addWire(NEW_ID);
559				} else
560					log_abort();
561				new_cell->setPort("\\" + port.first, sig);
562			}
563	
564			stats[stringf("%s cells to %s cells", cell_type, new_cell->type)]++;
565		}
566	
567		for (auto &stat: stats)
568			log("  mapped %d %s.\n", stat.second, stat.first);
569	}
